code = """import json

# Read funding data
disaster_funding = var_functions.query_db:20

# Read civic documents from file
civic_docs_file = var_functions.query_db:24
with open(civic_docs_file, 'r') as f:
    civic_docs = json.load(f)

# Map projects to amounts
project_amounts = {}
for rec in disaster_funding:
    project_amounts[rec['Project_Name']] = int(rec['Amount'])

# Find disaster projects starting in 2022
projects_in_2022 = []
for proj_name in project_amounts.keys():
    base_name = proj_name.split(' (')[0]
    for doc in civic_docs:
        text = doc.get('text', '')
        if base_name in text and '2022' in text:
            projects_in_2022.append(proj_name)
            break

# Sum funding
total = 0
for proj in projects_in_2022:
    total += project_amounts[proj]

output = {'total_funding': total}
print('__RESULT__:')
print(json.dumps(output))"""

